arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(0)
  if bActive=true and stunnedTime=0
  {
    jumpTime+=1
    if jumpTime=15
    {
      image_speed=0.5
      y+=2
      yVel=10
      if x>=oPlayer1.x {xVel=-4}
      else {xVel=4}
    }
    
    yVel-=0.4
    if isCollisionBottom(1)
    {
      yVel=-0.1
    }
    if isCollisionLeft(1)
      xVel*=-1
    if isCollisionRight(1)
      xVel*=-1
    if isCollisionTop(1)
    {
      if jumpTime>17 {jumpTime=0}
      image_speed=0.2
      xVel=0; yVel=0
    }
    
    moveTo(xVel,yVel)
    if isCollisionSolid() {y+=2}
    if y>room_height+24
    {
      if questType>0 {enemyQuest(questType)}
      instance_destroy()
    }
  }
  enemyStepEvent()
}
